#include <stdio.h>
#include <math.h>
int main() {
    int N, Q;
    scanf("%d", &N);
    int points[N][2];
    for (int i = 0; i < N; i++) {
        scanf("%d %d", &points[i][0], &points[i][1]);
    }
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        int l, r;
        scanf("%d %d", &l, &r);
        double maxDistance = 0;
        for (int j = l-1; j < r; j++) {
            for (int k = j+1; k < r; k++) {
                double distance = sqrt(pow(points[j][0]-points[k][0], 2) + pow(points[j][1]-points[k][1], 2));
                if (distance > maxDistance) {
                    maxDistance = distance;
                }
            }
        }
        printf("%lld\n", (long long)maxDistance*maxDistance);
    }
    return 0;
}

