code.JavaScript:
const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const N = parseInt(readline());
const points = [];
for (let i = 0; i < N; i++) {
    const [x, y] = readline().split(' ').map(Number);
    points.push([x, y]);
}
const Q = parseInt(readline());
for (let i = 0; i < Q; i++) {
    const [l, r] = readline().split(' ').map(Number);
    let maxDistance = 0;
    for (let j = l-1; j < r; j++) {
        for (let k = j+1; k < r; k++) {
            const distance = Math.sqrt(Math.pow(points[j][0]-points[k][0], 2) + Math.pow(points[j][1]-points[k][1], 2));
            if (distance > maxDistance) {
                maxDistance = distance;
            }
        }
    }
    console.log(Math.floor(maxDistance*maxDistance));
}

